rubric.en:
Expected code/algorithm:
isHexagonal(x) {
  if (x <= 0) failure;
  a = 1 + 8 * x;
  b = int(sqrt(a));
  if (b*b == a && (1+b)%4 == 0)
    return true;
  else
    return false;
}

