rubric.en:
Expected code/algorithm:
hasHexaPairs(s) {
  i = -1;
  for (k=0; k < s.size(); ++k)
    if (isHexagonal(s[k])) {
      if (i < 0)
        i = k;
      else
        return true;
    }
  return false;
}

